INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-001', 'USPS mailing identifiers', 'MA public records', 'SPR determination', 'SPR26/2112 describes a five-year request for USPS Mailer ID, CRID, permit numbers, postage meter/account numbers, and linked locations/vendors.', 'Past five years; Fall River Public Schools', 'Supervisor ordered response within 10 business days after nonresponse.', 'High', 'SPR26/2112');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-002', 'Hiring / licensure / start-date records', 'MA public records', 'SPR determinations', 'SPR26/1073 and SPR26/2117 show job postings, recruitment, interview records, waiver/licensure review, appointment/start-date, payroll authorization, and committee records as actual request categories.', 'Role-specific hiring periods; Fall River Public Schools', 'Supervisor ordered response within 10 business days in both matters.', 'High', 'SPR26/1073; SPR26/2117');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-003', 'Safety, restraint, staffing, and crisis records', 'MA public records with privacy overlay', 'SPR determination', 'SPR26/1074 lists incident reports, restraint reports, behavior summaries, staffing assignments, IEP-service staffing, event communications, emergency logs, crisis policies, training, and response records.', 'Aug. 1 2024-present; SY2024-25 and SY2025-26; Silvia Elementary', 'Supervisor ordered response within 10 business days after nonresponse.', 'High', 'SPR26/1074');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-004', 'Email search with full threads and metadata', 'MA public records', 'SPR boundary result', 'SPR26/2098 shows an email-search request for keyword hits, full threads, headers, metadata, and attachments. The appeal was closed because it was not framed as a records-law issue.', 'Apr. 27 2023 through processing date; East Bridgewater Public Schools', 'Useful request type; appeal must focus on search, response, withholding, fee, or format defects.', 'High', 'SPR26/2098');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-005', 'PRS aggregate complaint/intake export', 'MA public records', 'Direct production attachment', 'The PRS aggregate PDFs show columns for number, district/agency, intake date, status, letter-of-finding date, category, subcategory, and closure code.', 'Since Jan. 1 2021; statewide and Attleboro-specific exports', 'Responsive records were produced; supports requesting database-style exports.', 'High', 'PRS aggregate production thread and PDFs');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-006', 'PRS systemic-concern aggregate list', 'MA public records', 'Direct request text plus production thread', 'The thread includes request language seeking an aggregate list/export of PRS matters where a broader concern was identified during an individual complaint review.', 'Request said past three years; attached export covered records since Jan. 1 2021', 'Useful model; exact match between request and production still needs detailed comparison.', 'Medium-high', 'PRS systemic records thread');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-007', '766 school licensure and staffing leads', 'Cultivated / possible PRR', 'SPEDWatch thread', 'Thread discusses 766 staffing levels, certification lookup problems, initial licenses, extensions/waivers, CPR/monitoring, board terms, and succession. Reply says educator licensure history is public and DESE PRR can be used for district/school-specific records.', 'June 2026 thread; no formal records timeframe', 'Use as lead source only; verify through ELAR, DESE records, or district-held records.', 'Medium', '766 Teacher Certification thread');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-008', 'Time-out / calming / seclusion room procedures and tracking forms', 'Mixed: PRR plus PRS boundary', 'PRS NFA and technical-assistance PDFs', 'PRS 15554 NFA quotes a PRR for written policies, procedures, protocols, forms, logs, templates, and documents used to track these rooms/spaces. PRS closed because public-records issues are outside PRS purview.', 'Feb. 10 2026 PRR; March 2026 PRS/TA documents', 'Strong lane example: use PRR for records access; use PRS only for special-ed compliance framing beyond records access.', 'High', 'PRS 15554 NFA; TA PDF');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-009', 'IDEA Part B application / assurances / comment materials', 'Cultivated resource / possible PRR or FOIA', 'SPEDWatch thread', 'Thread points to DESE’s annual IDEA Part B application/assurances and public-comment deadline. It is a recurring report/resource type, not an SPR outcome.', 'Annual cycle; April 20 comment deadline in thread', 'Use as a cultivated resource and possible records category.', 'Medium', 'Part B Funds thread');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-010', 'PRS complainant-response and procedure materials', 'Cultivated / possible PRR', 'Attachment plus research paper', 'Chambers email attachment raises PRS complainant-response concerns; McKenna paper reports caregiver experiences with PRS transparency, timelines, findings of fact, and remedies.', 'May 2026 emails; 2026 paper', 'Use to support requests for PRS procedures, templates, training, and process guidance.', 'Medium', 'DESE-Chambers Emails; McKenna PRS paper');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-011', 'Special-ed incident/outcome datasets with high fee risk', 'MA public records with privacy overlay', 'Agency fee-response experience', 'SPR25/0822 and SPR25/0823 materials showed large search/redaction estimates for special-ed incident, outcome, IEP-goal, restraint/seclusion, and similar categories.', 'Jan. 2023-present in one example; other categories broader', 'Use aggregate fielded exports before broad record copies.', 'High', 'SPR25/0822; SPR25/0823 supplemental responses');
INSERT INTO aggregate_catalog (cat_id, category, lane, source_type, evidence_note, scope_seen, result_use, confidence, source_ref) VALUES ('CAT-012', 'Equitable services / private-school consultation packet', 'External shared example / possible PRR', 'Forwarded DESE response packet', 'Forward identified linked files: .msg request-materials email, FY26 written affirmation, FY26 IDEA grant attestation, and FY25 equitable-services monitoring workbook. Actual linked files still need download/review.', 'FY25/FY26 filenames; exact original request timeframe unknown', 'Keep in list as external/shared example, not assisted by Parent Data Force.', 'Medium', 'DESE/Hingham P005497-061726 forward');
